parameters.jsCode:
const vehicle = items[0].json.body;

// Armamos un texto técnico consolidado súper rico con todos los campos ACF exactos para los embeddings
let textRepresentation = `Vehículo: ${vehicle.title}\n`;
if (vehicle.subtitulo) textRepresentation += `Subtítulo: ${vehicle.subtitulo}\n`;
textRepresentation += `Marca: ${vehicle.brand}\n`;
if (vehicle.model) textRepresentation += `Modelo: ${vehicle.model}\n`;
textRepresentation += `Año: ${vehicle.year}\n`;
textRepresentation += `Precio: $${vehicle.price ? vehicle.price.toLocaleString('es-MX') : 'Consultar'} MXN\n`;
if (vehicle.price_special) textRepresentation += `Precio Especial (Descuento): $${vehicle.price_special.toLocaleString('es-MX')} MXN\n`;
textRepresentation += `Kilometraje: ${vehicle.mileage ? vehicle.mileage.toLocaleString('es-MX') : '0'} km\n`;
textRepresentation += `Transmisión: ${vehicle.transmission || 'No especificada'}\n`;
if (vehicle.engine_type) textRepresentation += `Tipo Motor: ${vehicle.engine_type}\n`;
if (vehicle.cilindros) textRepresentation += `Cilindros: ${vehicle.cilindros}\n`;
if (vehicle.puertas) textRepresentation += `Puertas: ${vehicle.puertas}\n`;
if (vehicle.color) textRepresentation += `Color Exterior: ${vehicle.color}\n`;
if (vehicle.color_interior) textRepresentation += `Color Interior: ${vehicle.color_interior}\n`;
if (vehicle.carroceria) textRepresentation += `Carrocería: ${vehicle.carroceria}\n`;
if (vehicle.features) textRepresentation += `Características adicionales: ${vehicle.features}\n`;
if (vehicle.downpayment) textRepresentation += `Enganche: ${vehicle.downpayment}\n`;
if (vehicle.financing_term) textRepresentation += `Plazo financiamiento: ${vehicle.financing_term}\n`;
if (vehicle.financing_info) textRepresentation += `Información de financiamiento: ${vehicle.financing_info}\n`;
if (vehicle.technical_sheet) textRepresentation += `Ficha Técnica (PDF): ${vehicle.technical_sheet}\n`;
textRepresentation += `Enlace: ${vehicle.permalink}\n\n`;
textRepresentation += `Descripción:\n${vehicle.description}`;

return [{
  json: {
    id: `wp-auto-${vehicle.id}`,
    title: vehicle.title,
    price: vehicle.price,
    price_special: vehicle.price_special,
    mileage: vehicle.mileage,
    year: vehicle.year,
    brand: vehicle.brand,
    model: vehicle.model,
    color: vehicle.color,
    transmission: vehicle.transmission,
    engine_type: vehicle.engine_type,
    featured_image: vehicle.featured_image,
    permalink: vehicle.permalink,
    textRepresentation: textRepresentation
  }
}];

